import{_ as e,o as r,c as t,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"光通訊追蹤日誌 — 2026-06-16（TST 05:00）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-16.md","filePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-16.md"}'),o={name:"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-16.md"};function i(h,a,n,d,s,p){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="光通訊追蹤日誌-—-2026-06-16-tst-05-00" tabindex="-1">光通訊追蹤日誌 — 2026-06-16（TST 05:00） <a class="header-anchor" href="#光通訊追蹤日誌-—-2026-06-16-tst-05-00" aria-label="Permalink to &quot;光通訊追蹤日誌 — 2026-06-16（TST 05:00）&quot;">​</a></h1><h2 id="本日敘事錨點" tabindex="-1">本日敘事錨點 <a class="header-anchor" href="#本日敘事錨點" aria-label="Permalink to &quot;本日敘事錨點&quot;">​</a></h2><p><strong>核心事件：AI 基礎建設資金持續擴大，光通訊需求結構未變。</strong></p><p>今天的全球新聞焦點是美伊框架協議與荷莫茲重開，這對光通訊並非直接驅動因子。但同時間，AI capex 與光纖/DCI 需求的結構性新聞仍持續釋出，代表即使短線市場情緒在交易地緣與油價，<strong>光通訊的中長期產業邏輯並沒有被破壞。</strong></p><p>今天的判斷重點是：</p><ol><li><strong>資金面仍在擴張</strong>：AI 債券發行、雲端資本支出上修、大型基建融資持續</li><li><strong>光纖與 DCI 需求仍在加速</strong>：AI 流量讓光纖從「配角」變「基礎建設主角」</li><li><strong>台灣個股面尚無新重大公告</strong>：今日重點在產業面與國際大廠動態</li></ol><p>簡單說，今天不是「光通訊新品日」，而是「產業需求訊號持續偏強」的一天。</p><p>查詢時間：2026-06-16 05:00 TST。</p><hr><h2 id="即時指標-4-項" tabindex="-1">即時指標（4 項） <a class="header-anchor" href="#即時指標-4-項" aria-label="Permalink to &quot;即時指標（4 項）&quot;">​</a></h2><h3 id="_1-輝達-gpu-光互連相關" tabindex="-1">1. 輝達 GPU / 光互連相關 <a class="header-anchor" href="#_1-輝達-gpu-光互連相關" aria-label="Permalink to &quot;1. 輝達 GPU / 光互連相關&quot;">​</a></h3><p>今日無新的 CPO / Silicon Photonics 產品公告。<br> 但從產業面看，輝達已與 Corning 簽署光連接長期合作，代表不只是做晶片，也在強化 AI 基礎建設的光纖與連接供應鏈。<br> 來源：RCR Wireless (2026-06-11)、24/7 Wall St. (2026-06-14)</p><h3 id="_2-博通-cpo-光網路動態" tabindex="-1">2. 博通 CPO / 光網路動態 <a class="header-anchor" href="#_2-博通-cpo-光網路動態" aria-label="Permalink to &quot;2. 博通 CPO / 光網路動態&quot;">​</a></h3><p>今日未取得 Taurus / CPO 的新公告。<br> 但博通已推出 350 億美元 AI 基建融資平台，代表 AI 網路基礎建設的資金與需求仍在放大。<br> 來源：WSJ (2026-06-09)、24/7 Wall St. (2026-06-14)</p><h3 id="_3-台積電先進封裝-光通訊相關" tabindex="-1">3. 台積電先進封裝 / 光通訊相關 <a class="header-anchor" href="#_3-台積電先進封裝-光通訊相關" aria-label="Permalink to &quot;3. 台積電先進封裝 / 光通訊相關&quot;">​</a></h3><p>今日無 COUPE / CoWoS 新公告。<br> 但台積電仍維持強勁營收與 AI 封裝需求結構，並持續被市場當作 AI 基建核心。<br> 來源：ANI News (2026-06-10)、MarketBeat (2026-06-11)</p><h3 id="_4-csp-資本支出" tabindex="-1">4. CSP 資本支出 <a class="header-anchor" href="#_4-csp-資本支出" aria-label="Permalink to &quot;4. CSP 資本支出&quot;">​</a></h3><p>本週最大產業訊號之一：</p><ul><li>Morgan Stanley 預估 2026 年 AI 相關債券發行將突破 5,000 億美元</li><li>Amazon 再取得 175 億美元貸款</li><li>Dell&#39;Oro 指出四大雲端廠 Q1 capex 年增 78% 這代表 AI 資本支出不是放緩，而是持續加速。<br> 來源：Reuters (2026-06-10)、Telecoms (2026-06-11)</li></ul><hr><h2 id="台灣供應鏈列表" tabindex="-1">台灣供應鏈列表 <a class="header-anchor" href="#台灣供應鏈列表" aria-label="Permalink to &quot;台灣供應鏈列表&quot;">​</a></h2><h3 id="聯亞-3081" tabindex="-1">聯亞 (3081) <a class="header-anchor" href="#聯亞-3081" aria-label="Permalink to &quot;聯亞 (3081)&quot;">​</a></h3><p>本日無法說會或新公告。</p><h3 id="光聖-6442" tabindex="-1">光聖 (6442) <a class="header-anchor" href="#光聖-6442" aria-label="Permalink to &quot;光聖 (6442)&quot;">​</a></h3><p>本日無法說會或新公告。</p><h3 id="上詮-3363" tabindex="-1">上詮 (3363) <a class="header-anchor" href="#上詮-3363" aria-label="Permalink to &quot;上詮 (3363)&quot;">​</a></h3><p>本日無法說會或新公告。</p><h3 id="智邦-2345" tabindex="-1">智邦 (2345) <a class="header-anchor" href="#智邦-2345" aria-label="Permalink to &quot;智邦 (2345)&quot;">​</a></h3><p>本日無法說會或新公告。</p><h3 id="其他台灣相關" tabindex="-1">其他台灣相關 <a class="header-anchor" href="#其他台灣相關" aria-label="Permalink to &quot;其他台灣相關&quot;">​</a></h3><p>Lintes (6715) 近期公告 AI 連接擴張與 6.4T CPC / CPO Socket 產品，顯示台灣供應鏈在 AI 光連接仍有持續布局。<br> 來源：FT / PR Newswire (2026-06-11)</p><hr><h2 id="產業趨勢摘要表" tabindex="-1">產業趨勢摘要表 <a class="header-anchor" href="#產業趨勢摘要表" aria-label="Permalink to &quot;產業趨勢摘要表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>趨勢</th><th>今日狀態</th></tr></thead><tbody><tr><td>銅退光進</td><td>🟢 維持：AI 流量持續推升光纖需求</td></tr><tr><td>2026 商轉元年</td><td>🟡 觀察：產業資金加速，但仍以 pre-deploy / 建置為主</td></tr><tr><td>OCI-MSA / CPO</td><td>🟡 觀察：今日無新進度公告</td></tr></tbody></table><hr><h2 id="今日觀察" tabindex="-1">今日觀察 <a class="header-anchor" href="#今日觀察" aria-label="Permalink to &quot;今日觀察&quot;">​</a></h2><p>今天如果只看「新品」或「法說」，會覺得光通訊很安靜。<br> 但如果看「產業資金」與「基礎建設」，其實訊號很強：</p><ul><li>Nvidia 強化光連接</li><li>Broadcom 強化 AI 網路基建融資</li><li>Amazon 加速貸款籌資</li><li>Corning 被多方大廠包夾採購</li><li>Dell&#39;Oro 再次確認 DCI 光設備需求成長 40%</li></ul><p>這代表現在的光通訊不是「題材炒完」，而是「從題材進入建設期」。<br> 後續要觀察的不再是「會不會有需求」，而是「誰先量產、誰先通過客戶驗證」。</p><p>查詢時間：2026-06-16 05:00 TST。</p><hr><h2 id="延續昨日敘事" tabindex="-1">延續昨日敘事 <a class="header-anchor" href="#延續昨日敘事" aria-label="Permalink to &quot;延續昨日敘事&quot;">​</a></h2><p>昨日後續重點在於 AI capex 與網路基礎建設是否持續擴張。<br> 今天確認：資金面持續加速，光纖與 DCI 需求偏強。<br> 台灣個股面暫無新重大更新，後續觀察法說與客戶驗證進度。</p><p>查詢時間：2026-06-16 05:00 TST。</p>',44)])])}const u=e(o,[["render",i]]);export{b as __pageData,u as default};
